<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/portal_estudiante_layout.php';require_once dirname(__DIR__,2).'/includes/portal_estudiante_aula.php';$portal=portalEstudianteCabecera('Mi clase','clase','Docentes, secciones, horarios y estado de tus matrículas.');$filas=aulaInscripcionesEstudiante(obtenerConexion(),(int)$portal['perfil']['id']);?>
<div class="row g-4"><?php foreach($filas as$f):?><div class="col-lg-6"><article class="card h-100"><div class="card-body"><div class="d-flex justify-content-between gap-2"><span class="badge bg-primary"><?=atenea_e($f['codigo'])?></span><span class="badge bg-<?=$f['estado']==='inscrito'?'success':($f['estado']==='pendiente_asignacion'?'warning':'secondary')?>"><?=atenea_e(ucfirst(str_replace('_',' ',$f['estado'])))?></span></div><h2 class="h4 mt-3"><?=atenea_e($f['nombre'])?></h2><?php if($f['estado']==='pendiente_asignacion'):?><div class="alert alert-warning">Tu pago está confirmado y la asignación de docente y sección sigue pendiente.</div><?php else:?><dl class="row mb-3"><dt class="col-4">Docente</dt><dd class="col-8"><?=atenea_e((string)($f['docente']?:'Por asignar'))?></dd><dt class="col-4">Sección</dt><dd class="col-8"><?=atenea_e((string)$f['seccion'])?></dd><dt class="col-4">Horario</dt><dd class="col-8"><?=atenea_e((string)($f['horario']?:'Por publicar'))?></dd><dt class="col-4">Periodo</dt><dd class="col-8"><?=atenea_e($f['fecha_inicio']?date('d/m/Y',strtotime($f['fecha_inicio'])):'Por definir')?> – <?=atenea_e($f['fecha_finalizacion']?date('d/m/Y',strtotime($f['fecha_finalizacion'])):'Por definir')?></dd></dl><a class="btn btn-primary" href="<?=atenea_url('src/estudiantes/curso.php?id='.(int)$f['asignatura_id'])?>">Abrir aula de la clase</a> <a class="btn btn-outline-primary" href="<?=atenea_url('src/comunicaciones/agenda.php?rol=docente&capacitacion='.(int)$f['asignatura_id'])?>">Contactar docente</a><?php endif;?></div></article></div><?php endforeach;?><?php if(!$filas):?><div class="col-12"><div class="card"><div class="aula-empty"><i class="bi bi-people"></i><h2 class="h5 mt-3">No tienes una clase asignada</h2><p class="mb-0">Las matrículas confirmadas aparecerán aquí sin usar información simulada.</p></div></div></div><?php endif;?></div><?php portalEstudiantePie();
